// Authored translations for the Leadership Skills Assessment tool.
// Deep-merges the `leadership` namespace into each non-English messages/<loc>.json.
// ICU placeholders ({part} {title} {n} {name} {done} {total} {avg} {band} {v})
// and <b> tags are preserved verbatim. Run: node scripts/translate-leadership.mjs
import { readFileSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const here = dirname(fileURLToPath(import.meta.url));
const msgDir = resolve(here, "..", "messages");

function deepMerge(base, override) {
  const out = { ...base };
  for (const k of Object.keys(override)) {
    const b = base[k];
    const o = override[k];
    if (b && o && typeof b === "object" && typeof o === "object" && !Array.isArray(b) && !Array.isArray(o)) {
      out[k] = deepMerge(b, o);
    } else {
      out[k] = o;
    }
  }
  return out;
}

